import{_ as e,o as l,c as a,ag as d}from"./chunks/framework.BDReElpY.js";const f=JSON.parse('{"title":"Silicon Operators","description":"","frontmatter":{},"headers":[],"relativePath":"archive/silicon/operators.md","filePath":"archive/silicon/operators.md"}'),i={name:"archive/silicon/operators.md"};function s(n,t,o,r,c,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="silicon-operators" tabindex="-1">Silicon Operators <a class="header-anchor" href="#silicon-operators" aria-label="Permalink to &quot;Silicon Operators&quot;">​</a></h1><p>Vex includes a rich set of operators designed specifically for vector, matrix, and signal processing operations. These operators compile maps directly to efficient hardware instructions.</p><h2 id="_1-advanced-arithmetic" tabindex="-1">1. Advanced Arithmetic <a class="header-anchor" href="#_1-advanced-arithmetic" aria-label="Permalink to &quot;1. Advanced Arithmetic&quot;">​</a></h2><h3 id="saturating-arithmetic" tabindex="-1">Saturating Arithmetic <a class="header-anchor" href="#saturating-arithmetic" aria-label="Permalink to &quot;Saturating Arithmetic&quot;">​</a></h3><p>Prevents overflow/underflow by clamping values at the type&#39;s minimum/maximum instead of wrapping.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">`+</td><td style="text-align:left;">`</td><td style="text-align:left;">Sat Add</td><td style="text-align:left;">`a +</td></tr><tr><td style="text-align:left;">`-</td><td style="text-align:left;">`</td><td style="text-align:left;">Sat Sub</td><td style="text-align:left;">`a -</td></tr><tr><td style="text-align:left;">`*</td><td style="text-align:left;">`</td><td style="text-align:left;">Sat Mul</td><td style="text-align:left;">`a *</td></tr></tbody></table><h3 id="element-wise-min-max-clamp" tabindex="-1">Element-wise Min/Max/Clamp <a class="header-anchor" href="#element-wise-min-max-clamp" aria-label="Permalink to &quot;Element-wise Min/Max/Clamp&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;?</code></td><td style="text-align:left;">Min</td><td style="text-align:left;"><code>a &lt;? b</code></td><td style="text-align:left;">Element-wise minimum (<code>min(a, b)</code>).</td></tr><tr><td style="text-align:left;"><code>&gt;?</code></td><td style="text-align:left;">Max</td><td style="text-align:left;"><code>a &gt;? b</code></td><td style="text-align:left;">Element-wise maximum (<code>max(a, b)</code>).</td></tr><tr><td style="text-align:left;"><code>&gt;&lt;</code></td><td style="text-align:left;">Clamp</td><td style="text-align:left;"><code>x &gt;&lt; [0, 1]</code></td><td style="text-align:left;">Clamp value to range.</td></tr></tbody></table><h2 id="_2-linear-algebra" tabindex="-1">2. Linear Algebra <a class="header-anchor" href="#_2-linear-algebra" aria-label="Permalink to &quot;2. Linear Algebra&quot;">​</a></h2><p>Linear algebra operations are distinct from element-wise operations to avoid ambiguity.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;*&gt;</code></td><td style="text-align:left;">MatMul</td><td style="text-align:left;"><code>A &lt;*&gt; B</code></td><td style="text-align:left;">Matrix Multiplication ($A \\times B$).</td></tr><tr><td style="text-align:left;"><code>&lt;\\&gt;</code></td><td style="text-align:left;">Solve</td><td style="text-align:left;"><code>A &lt;\\&gt; b</code></td><td style="text-align:left;">Solve linear system $Ax = b$.</td></tr><tr><td style="text-align:left;"><code>&lt;^&gt;</code></td><td style="text-align:left;">Power</td><td style="text-align:left;"><code>A &lt;^&gt; 3</code></td><td style="text-align:left;">Matrix power ($A^3$).</td></tr><tr><td style="text-align:left;"><code>&#39;</code></td><td style="text-align:left;">Transpose</td><td style="text-align:left;"><code>A&#39;</code></td><td style="text-align:left;">Matrix transpose ($A^T$).</td></tr><tr><td style="text-align:left;"><code>×</code></td><td style="text-align:left;">Cross</td><td style="text-align:left;"><code>a × b</code></td><td style="text-align:left;">Vector cross product (3D).</td></tr><tr><td style="text-align:left;"><code>·</code></td><td style="text-align:left;">Dot</td><td style="text-align:left;"><code>a · b</code></td><td style="text-align:left;">Dot product (scalar product).</td></tr></tbody></table><h2 id="_3-reduction-operators" tabindex="-1">3. Reduction Operators <a class="header-anchor" href="#_3-reduction-operators" aria-label="Permalink to &quot;3. Reduction Operators&quot;">​</a></h2><p>Unary operators that reduce a vector to a scalar.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>\\+</code></td><td style="text-align:left;">Sum</td><td style="text-align:left;"><code>\\+vec</code></td><td style="text-align:left;">Sum of all elements ($\\sum x_i$).</td></tr><tr><td style="text-align:left;"><code>\\*</code></td><td style="text-align:left;">Product</td><td style="text-align:left;"><code>\\*vec</code></td><td style="text-align:left;">Product of all elements ($\\prod x_i$).</td></tr><tr><td style="text-align:left;"><code>\\&gt;</code></td><td style="text-align:left;">Max</td><td style="text-align:left;"><code>\\&gt;vec</code></td><td style="text-align:left;">Maximum element.</td></tr><tr><td style="text-align:left;"><code>\\&lt;</code></td><td style="text-align:left;">Min</td><td style="text-align:left;"><code>\\&lt;vec</code></td><td style="text-align:left;">Minimum element.</td></tr><tr><td style="text-align:left;"><code>\\&amp;</code></td><td style="text-align:left;">All</td><td style="text-align:left;"><code>\\&amp;mask</code></td><td style="text-align:left;">True if all elements are true.</td></tr><tr><td style="text-align:left;"><code>|</code></td><td style="text-align:left;">Any</td><td style="text-align:left;"><code>|mask</code></td><td style="text-align:left;">True if any element is true.</td></tr></tbody></table><h2 id="_4-signal-processing-bitwise" tabindex="-1">4. Signal Processing &amp; Bitwise <a class="header-anchor" href="#_4-signal-processing-bitwise" aria-label="Permalink to &quot;4. Signal Processing &amp; Bitwise&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;&lt;&lt;</code></td><td style="text-align:left;">Rotate L</td><td style="text-align:left;"><code>a &lt;&lt;&lt; 3</code></td><td style="text-align:left;">Bitwise rotation left.</td></tr><tr><td style="text-align:left;"><code>&gt;&gt;&gt;</code></td><td style="text-align:left;">Rotate R</td><td style="text-align:left;"><code>a &gt;&gt;&gt; 3</code></td><td style="text-align:left;">Bitwise rotation right.</td></tr><tr><td style="text-align:left;"><code>*^</code></td><td style="text-align:left;">Galois Mul</td><td style="text-align:left;"><code>a *^ b</code></td><td style="text-align:left;">Carry-less multiplication (for Cryptography/CRC).</td></tr><tr><td style="text-align:left;"><code>[::s]</code></td><td style="text-align:left;">Stride</td><td style="text-align:left;"><code>arr[::2]</code></td><td style="text-align:left;">Slice with stride.</td></tr></tbody></table><h2 id="_5-broadcasting" tabindex="-1">5. Broadcasting <a class="header-anchor" href="#_5-broadcasting" aria-label="Permalink to &quot;5. Broadcasting&quot;">​</a></h2><p>Vex supports NumPy-style broadcasting rules for element-wise operations.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Scalar + Vector -&gt; Vector</span></span>\n<span class="line"><span>[1, 2, 3] + 10          // [11, 12, 13]</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>// Vector + Matrix -&gt; Matrix (row broadcast)</span></span>\n<span class="line"><span>let row = [1, 2, 3]</span></span>\n<span class="line"><span>let mat = [[10, 20, 30], [40, 50, 60]]</span></span>\n<span class="line"><span>row + mat               // [[11, 22, 33], [41, 52, 63]]</span></span></code></pre></div><h2 id="operator-precedence" tabindex="-1">Operator Precedence <a class="header-anchor" href="#operator-precedence" aria-label="Permalink to &quot;Operator Precedence&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Priority</th><th style="text-align:left;">Operators</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>High</strong></td><td style="text-align:left;"><code>&#39;</code> (Transpose), <code>#</code> (Length)</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">Unary: <code>-</code>, <code>~</code>, <code>\\+</code>, <code>\\*</code> ...</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">Power: <code>^</code>, <code>**</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">Multiply: <code>*</code>, <code>/</code>, <code>&lt;*&gt;</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">Add: <code>+</code>, <code>-</code>, `+</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;">Shift/Rotate: <code>&lt;&lt;</code>, <code>&gt;&gt;&gt;</code></td></tr><tr><td style="text-align:left;"><strong>Low</strong></td><td style="text-align:left;">Compare, Logic, Assign</td></tr></tbody></table>',21)])])}const y=e(i,[["render",s]]);export{f as __pageData,y as default};
